import type { ToolProvider, PromptProvider } from 'agentfootprint';

// Dynamic tool provider — tools change based on conversation state
const dynamicTools: ToolProvider = {
  resolve: (ctx) => {
    const verified = ctx.messages.some(m =>
      m.role === 'tool' && m.content.includes('"verified":true'));

    const basic = [lookupOrder, checkInventory, verifyIdentity];
    const admin = [issueRefund, escalateToManager];

    if (verified) {
      return { value: [...basic, ...admin], chosen: 'elevated', rationale: 'identity verified' };
    }
    return { value: basic, chosen: 'basic', rationale: 'standard access' };
  },
};

// Dynamic prompt — changes after verification
const dynamicPrompt: PromptProvider = {
  resolve: (ctx) => {
    const verified = ctx.history.some(m =>
      typeof m.content === 'string' && m.content.includes('"verified":true'));

    if (verified) {
      return {
        value: 'You are a SENIOR support agent with ELEVATED ACCESS. You can issue refunds and escalate.',
        chosen: 'elevated',
        rationale: 'identity verified',
      };
    }
    return {
      value: 'You are a support agent. Verify identity before issuing refunds.',
      chosen: 'standard',
    };
  },
};

const agent = Agent.create({ provider: anthropic('claude-sonnet-4-20250514') })
  .pattern(AgentPattern.Dynamic)     // re-evaluate all slots each iteration
  .toolProvider(dynamicTools)         // tools change after verification
  .promptProvider(dynamicPrompt)      // prompt changes after verification
  .build();

// Turn 1: lookup_order → flagged
// Turn 2: verify_identity → verified
// Turn 3: issue_refund now available!`}];function sV(){return nV.map(t=>({category:t,presets:rV.filter(e=>e.category===t.id)})).filter(t=>t.presets.length>0)}const T_={"llm-call":"✨",agent:"🤖",rag:"🔍",swarm:"🐝"},C_={"llm-call":"LLM Call",agent:"Agent",rag:"RAG",swarm:"Swarm"};function oV({activePresetId:t,onSelect:e,onViewCode:n,disabled:r}){const[o,a]=I.useState(!1),l=I.useRef(null),u=I.useMemo(()=>sV(),[]),d=I.useMemo(()=>{for(const p of u){const g=p.presets.find(m=>m.id===t);if(g)return g}return null},[u,t]);return I.useEffect(()=>{if(!o)return;const p=g=>{l.current&&!l.current.contains(g.target)&&a(!1)};return document.addEventListener("mousedown",p),()=>document.removeEventListener("mousedown",p)},[o]),I.useEffect(()=>{if(!o)return;const p=g=>{g.key==="Escape"&&a(!1)};return document.addEventListener("keydown",p),()=>document.removeEventListener("keydown",p)},[o]),v.jsxs("div",{className:"preset-selector",ref:l,children:[v.jsxs("button",{className:`preset-trigger ${o?"preset-trigger--open":""} ${d?"preset-trigger--active":""}`,onClick:()=>!r&&a(!o),disabled:r,type:"button",children:[d?v.jsxs(v.Fragment,{children:[v.jsx("span",{className:"preset-trigger-icon",children:T_[d.pattern]}),v.jsxs("span",{className:"preset-trigger-content",children:[v.jsx("span",{className:"preset-trigger-label",children:d.label}),v.jsx("span",{className:"preset-trigger-pattern",children:C_[d.pattern]})]})]}):v.jsx("span",{className:"preset-trigger-placeholder",children:"Choose an example to explore..."}),v.jsx("span",{className:`preset-trigger-chevron ${o?"preset-trigger-chevron--open":""}`,children:"▾"})]}),o&&v.jsx("div",{className:"preset-dropdown",children:u.map(({category:p,presets:g})=>v.jsxs("div",{className:"preset-group",children:[v.jsxs("div",{className:"preset-group-header",children:[v.jsx("span",{className:"preset-group-label",children:p.label}),v.jsx("span",{className:"preset-group-desc",children:p.description})]}),g.map(m=>v.jsxs("button",{className:`preset-item ${t===m